import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"附录 C：名词解释","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-c-glossary.md","filePath":"chapters/appendix-c-glossary.md"}'),c={name:"chapters/appendix-c-glossary.md"};function a(n,t,s,i,l,m){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="附录-c-名词解释" tabindex="-1">附录 C：名词解释 <a class="header-anchor" href="#附录-c-名词解释" aria-label="Permalink to &quot;附录 C：名词解释&quot;">​</a></h1><blockquote><p>本附录收录了 qmd 源码和本书中出现的专业术语，按英文字母顺序排列。每个术语标注英文全称和中文解释，方便读者在阅读过程中随时查阅。</p></blockquote><h2 id="术语表" tabindex="-1">术语表 <a class="header-anchor" href="#术语表" aria-label="Permalink to &quot;术语表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>英文全称</th><th>解释</th></tr></thead><tbody><tr><td>BM25</td><td>Best Matching 25</td><td>一种经典的概率信息检索排名函数，由 Stephen Robertson 等人提出。qmd 通过 SQLite FTS5 内置的 <code>bm25()</code> 函数实现，在 <code>src/store.ts</code> 的 <code>searchFTS()</code> 中使用。它根据词频（TF）、逆文档频率（IDF）和文档长度对查询词的匹配程度打分。相比简单的 TF-IDF，BM25 对高频词有饱和效应，避免了长文档的不公平优势。</td></tr><tr><td>Content-Addressable Storage</td><td>内容寻址存储</td><td>一种以数据内容的哈希值作为存储地址的策略。qmd 的 <code>content</code> 表（<code>src/store.ts</code> L659）使用 SHA-256 哈希作为主键，相同内容无论路径如何变化都只存储一份。这在多个虚拟路径指向同一文件时自动实现了去重。</td></tr><tr><td>Cosine Distance</td><td>余弦距离</td><td>衡量两个向量方向差异的距离度量，定义为 <code>1 - cosine_similarity</code>。值为 0 表示完全相同方向，值为 1 表示正交。qmd 在 sqlite-vec 虚拟表中指定 <code>distance_metric=cosine</code>，向量检索返回的分数通过 <code>1 - cosine_distance</code> 转换为相似度。</td></tr><tr><td>Cross-Encoder</td><td>交叉编码器</td><td>一种将查询和文档拼接后整体编码的重排序模型，与 Bi-Encoder（双编码器，分别编码查询和文档）相对。Cross-Encoder 能捕捉查询与文档之间更精细的交互特征，但推理成本较高，因此只用于对候选结果集做精排。qmd 使用 <code>qwen3-reranker-0.6b-q8_0.gguf</code> 模型在本地执行 Cross-Encoder 重排。</td></tr><tr><td>Docid</td><td>Document Identifier（文档标识符）</td><td>qmd 中每个文档的唯一标识，采用 <code>qmd://collection/path</code> 格式的虚拟路径。Docid 与文件系统的真实路径解耦，允许同一文件在不同集合中有不同的标识。</td></tr><tr><td>Embedding</td><td>嵌入/嵌入向量</td><td>将文本映射到高维实数向量空间的过程及其产物。语义相近的文本在向量空间中距离更近。qmd 使用 <code>embeddinggemma-300M-Q8_0.gguf</code> 模型在本地生成嵌入，通过 <code>src/llm.ts</code> 的 <code>embedBatch()</code> 方法批量处理。</td></tr><tr><td>FTS5</td><td>Full-Text Search 5</td><td>SQLite 的第五代全文搜索扩展。qmd 创建了 <code>documents_fts</code> 虚拟表（<code>src/store.ts</code> L764），使用 <code>porter unicode61</code> 分词器，同时支持英文词干提取和 Unicode 文本。FTS5 提供内置的 <code>bm25()</code> 评分函数和 <code>highlight()</code>、<code>snippet()</code> 辅助函数。</td></tr><tr><td>GGUF</td><td>GPT-Generated Unified Format</td><td>一种用于存储大语言模型权重的文件格式，由 llama.cpp 社区开发。GGUF 支持多种量化精度（Q4、Q8 等），qmd 依赖 node-llama-cpp 加载 GGUF 格式模型，通过 HuggingFace URI 引用并自动下载到 <code>~/.cache/qmd/models</code>。</td></tr><tr><td>HyDE</td><td>Hypothetical Document Embedding</td><td>一种查询扩展策略。LLM 根据原始查询生成一篇&quot;假设文档&quot;——即如果答案存在，它可能长什么样。然后用这篇假设文档的嵌入向量去执行向量检索，往往比直接用短查询嵌入更能匹配真实的相关文档。在 <code>ExpandedQuery</code> 类型中 <code>type: &#39;hyde&#39;</code> 标识此策略。</td></tr><tr><td>Intent</td><td>查询意图</td><td>用户查询背后的真实目的。qmd 的查询扩展模型（<code>qmd-query-expansion-1.7B-q4_k_m.gguf</code>）会分析查询意图，据此生成词汇扩展（lex）和语义扩展（vec）两种补充查询，提升召回率。</td></tr><tr><td>Lex Query</td><td>Lexical Query（词汇查询）</td><td>基于关键词匹配的查询方式，对应 BM25 全文检索路径。在 <code>ExpandedQuery</code> 类型中 <code>type: &#39;lex&#39;</code> 标识词汇扩展——LLM 为原始查询添加同义词或相关关键词，扩大 FTS5 的匹配范围。</td></tr><tr><td>MCP</td><td>Model Context Protocol（模型上下文协议）</td><td>Anthropic 提出的一种标准协议，允许 AI Agent（如 Claude）通过标准化接口调用外部工具。qmd 的 <code>src/mcp.ts</code> 实现了 MCP 服务器，将搜索、获取文档等能力注册为 MCP 工具，支持 HTTP 和 stdio 两种传输方式。</td></tr><tr><td>node-llama-cpp</td><td>—</td><td>一个 Node.js/Bun 原生绑定库，封装了 llama.cpp 推理引擎。qmd 通过 <code>src/llm.ts</code> 的 <code>LlamaCpp</code> 类使用它加载 GGUF 模型，执行嵌入生成、查询扩展和重排序三种推理任务。支持 GPU 加速和动态批处理。</td></tr><tr><td>Porter Stemmer</td><td>Porter 词干提取器</td><td>一种经典的英文词干提取算法，由 Martin Porter 于 1980 年提出。它将英文单词还原为词干形式（如 &quot;running&quot; → &quot;run&quot;），使得搜索 &quot;search&quot; 也能匹配到 &quot;searching&quot;、&quot;searched&quot;。qmd 的 FTS5 虚拟表通过 <code>tokenize=&#39;porter unicode61&#39;</code> 启用此功能。</td></tr><tr><td>Position-Aware Blending</td><td>位置感知混合</td><td>qmd 混合查询管线中的一项优化策略。在 RRF 融合过程中，不仅考虑各路搜索结果的排名，还会根据结果在原始文档中的位置信息调整权重。例如，出现在文档标题或开头的匹配通常获得更高的融合分数。</td></tr><tr><td>Query Expansion</td><td>查询扩展</td><td>在用户原始查询的基础上自动生成补充查询，以提升搜索召回率的技术。qmd 使用本地 LLM 模型生成三种扩展：词汇扩展（lex）添加同义词关键词，语义扩展（vec）改写查询以捕捉不同表述，HyDE 生成假设文档嵌入。扩展结果通过 <code>ExpandedQuery</code> 类型表示。</td></tr><tr><td>Reciprocal Rank Fusion (RRF)</td><td>倒数排名融合</td><td>一种将多路搜索结果合并排序的算法。对于每个文档，计算其在各路搜索中排名的倒数之和：<code>score = Σ 1/(k + rank)</code>，其中 k 是平滑参数（通常为 60）。RRF 的优点是不依赖各路搜索的绝对分数（它们可能量纲不同），只利用相对排名，天然适合融合 BM25 和向量搜索这类异构结果。</td></tr><tr><td>Reranking</td><td>重排序</td><td>在初步检索（召回）之后，使用更精确但更昂贵的模型对候选结果重新排序的过程。qmd 使用 Cross-Encoder 模型（Qwen3-Reranker）对 RRF 融合后的 Top-N 结果做精排，通常能显著提升排序质量。</td></tr><tr><td>Smart Chunking</td><td>智能分块</td><td>qmd 将长文档切分为适合嵌入的片段时使用的算法。与固定长度切分不同，智能分块在目标位置附近的搜索窗口内寻找最佳断点（如 Markdown 标题、代码块边界、段落分隔符），使用距离衰减加权评分 <code>1.0 - (distance/window)^2 * 0.7</code> 来平衡断点质量与位置。参见 <code>src/store.ts</code> 中的 <code>findBestCutoff()</code> 函数（L384）。</td></tr><tr><td>sqlite-vec</td><td>—</td><td>一个 SQLite 扩展，为 SQLite 添加向量搜索能力。它提供 <code>vec0</code> 虚拟表类型，支持余弦距离、L2 距离等度量方式的近邻查询。qmd 在 <code>src/db.ts</code> 中加载此扩展，在 <code>src/store.ts</code> 中创建 <code>vectors_vec</code> 虚拟表存储文档嵌入向量。</td></tr><tr><td>Strong Signal</td><td>强信号</td><td>qmd 混合查询管线中的一种优化机制。当某个文档在 BM25 或向量搜索中获得极高分数（超过预设阈值）时，系统会将其标记为&quot;强信号&quot;，在 RRF 融合时给予额外加权，确保高置信度的匹配不会因为另一路搜索中排名较低而被埋没。</td></tr><tr><td>Token Bucket</td><td>令牌桶</td><td>一种经典的流量控制算法。qmd 在批量嵌入操作中使用令牌桶来限制对 LLM 推理引擎的并发调用速率，防止内存溢出或 GPU 资源争抢。桶中的令牌以固定速率补充，每次推理调用消耗一个令牌。</td></tr><tr><td>Vec Query</td><td>Vector Query（向量查询）</td><td>基于语义相似度的查询方式，对应向量检索路径。在 <code>ExpandedQuery</code> 类型中 <code>type: &#39;vec&#39;</code> 标识语义扩展。向量查询先将查询文本通过嵌入模型转为向量，再在 sqlite-vec 中检索余弦距离最近的文档分块。</td></tr><tr><td>Virtual Path (qmd://)</td><td>虚拟路径</td><td>qmd 用于标识文档的 URI 格式，形如 <code>qmd://collection-name/relative/path.md</code>。虚拟路径将文档标识与文件系统真实路径解耦，使得同一文件可以在不同集合中拥有不同身份。所有 API 返回的 <code>docid</code> 字段均使用虚拟路径格式。</td></tr><tr><td>WAL</td><td>Write-Ahead Logging（预写日志）</td><td>SQLite 的一种日志模式。在 WAL 模式下，修改操作先写入独立的日志文件，读操作可以与写操作并发执行，不会互相阻塞。qmd 在 <code>initializeDatabase()</code> 中通过 <code>PRAGMA journal_mode=WAL</code>（<code>src/store.ts</code> L651）启用此模式，确保在索引文档的同时能响应搜索查询。</td></tr></tbody></table><h2 id="缩写对照表" tabindex="-1">缩写对照表 <a class="header-anchor" href="#缩写对照表" aria-label="Permalink to &quot;缩写对照表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>缩写</th><th>全称</th><th style="text-align:center;">首次出现章节</th></tr></thead><tbody><tr><td>BM25</td><td>Best Matching 25</td><td style="text-align:center;">第 1 章</td></tr><tr><td>CAS</td><td>Content-Addressable Storage</td><td style="text-align:center;">第 4 章</td></tr><tr><td>FTS</td><td>Full-Text Search</td><td style="text-align:center;">第 1 章</td></tr><tr><td>GGUF</td><td>GPT-Generated Unified Format</td><td style="text-align:center;">第 1 章</td></tr><tr><td>HyDE</td><td>Hypothetical Document Embedding</td><td style="text-align:center;">第 11 章</td></tr><tr><td>IDF</td><td>Inverse Document Frequency</td><td style="text-align:center;">第 7 章</td></tr><tr><td>MCP</td><td>Model Context Protocol</td><td style="text-align:center;">第 1 章</td></tr><tr><td>RRF</td><td>Reciprocal Rank Fusion</td><td style="text-align:center;">第 1 章</td></tr><tr><td>TF</td><td>Term Frequency</td><td style="text-align:center;">第 7 章</td></tr><tr><td>VRAM</td><td>Video Random Access Memory</td><td style="text-align:center;">第 9 章</td></tr><tr><td>WAL</td><td>Write-Ahead Logging</td><td style="text-align:center;">第 4 章</td></tr></tbody></table>',6)])])}const q=d(c,[["render",a]]);export{h as __pageData,q as default};
